6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This is a very basic asynchronous FIFO. The clocks can be fully asynchronous
11	-- (unrelated). It  has optional level- and almost-full/empty ports.
12	
13	library ieee;
14	use ieee.std_logic_1164.all;
15	use ieee.numeric_std.all;
16	
17	use work.psi_common_logic_pkg.all;
18	use work.psi_common_math_pkg.all;
19	--@formatter:off
20	entity psi_common_async_fifo is
21	  generic(width_g         : positive  := 16;                                         -- Width of the FIFO|
22	          depth_g         : positive  := 32;                                         -- Depth of the FIFO|
23	          afull_on_g      : boolean   := false;                                      -- **True** = Almost full output is provided, **False** = Almost full output is omitted|
24	          afull_lvl_g     : natural   := 28;                                         -- Almost full output is high if the level is \>= AlmFullLevel\_g|
25	          aempty_on_g     : boolean   := false;                                      -- True = Almost empty output is provided, False = Almost empty output is omitted|
26	          aempty_level_g  : natural   := 4;                                          -- Almost empty output is high if the level is \<= AlmFullLevel\_g|
27	          ram_style_g     : string    := "auto";                                     -- **"auto"** (default) Automatic choice of block- or distributed-RAM **"distributed"** Use distributed RAM (LUT-RAM), **"block"** Use block RAM|
28	          ram_behavior_g  : string    := "RBW";                                      -- **"RBW"** Read-before-write implementation, **"WBR"** Write-before-read implementation|
29	          rdy_rst_state_g : std_logic := '1';                                        -- State of *InRdy* signal during reset. Usually this does not play a role and the default setting ('1') that leads to the least logic on the InRdy path is fine. Setting the value to '0' may lead to less optimal performance in terms of FMAX.
30	          rst_pol_g       : std_logic := '1');                                       -- reset polarity, '1' high active & '0' low active|
31	  port(   -- Control Ports
32	          in_clk_i     : in  std_logic;                                               --    Write side clock
33	          in_rst_i     : in  std_logic;                                               --    Write side reset input (active high)
34	          out_clk_i    : in  std_logic;                                               --    Read side clock
35	          out_rst_i    : in  std_logic;                                               --    Read side reset  input (active high)
36	          -- data
37	          in_dat_i     : in  std_logic_vector(width_g - 1 downto 0);                  --    Write data
38	          in_vld_i     : in  std_logic;                                               --    AXI-S  handshaking signal
39	          in_rdy_o     : out std_logic;       -- not full                             --    AXI-S  handshaking signal
40	          out_dat_o    : out std_logic_vector(width_g - 1 downto 0);                  --    Read data
41	          out_vld_o    : out std_logic;       -- not empty                            --    AXI-S  handshaking signal
42	          out_rdy_i    : in  std_logic;                                               --    AXI-S handshaking signal
43	          -- status signal in
44	          in_full_o    : out std_logic;                                               --    FIFO full signal synchronous to *in_clk_i*
45	          in_empty_o   : out std_logic;                                               --    FIFO empty signal synchronous to *in_clk_i*
46	          in_afull_o   : out std_logic;                                               --    FIFO almost full signal synchronous to *in_clk_i*, Only exists if *AlmFullOn\_g*  = true
47	          in_aempty_o  : out std_logic;                                               --    FIFO almost empty signal synchronous to *in_clk_i*, Only exists if   *AlmEmptyOn\_g* = true|
48	          in_lvl_o     : out std_logic_vector(log2ceil(depth_g + 1) - 1 downto 0);    --    FIFO level synchronous to  *in_clk_i*
49	          out_full_o   : out std_logic;                                               --    FIFO full  signal  synchronous to *out_clk_i*
50	          out_empty_o  : out std_logic;                                               --    FIFO empty signal   synchronous to *out_clk_i*        |
51	          out_afull_o  : out std_logic;                                               --    FIFO almost full signal synchronous to *out_clk_i* Only exists if *AlmFullOn\_g* = true
52	          out_aempty_o : out std_logic;                                               --    FIFO almost   empty signal  synchronous to *out_clk_i*  Only exists if  *AlmEmptyOn\_g* = true
53	          out_lvl_o    : out std_logic_vector(log2ceil(depth_g + 1) - 1 downto 0));   --    FIFO level synchronous to   *out_clk_i*
54	end entity;
55	--@formatter:on
56	
57	architecture rtl of psi_common_async_fifo is
58	
59	  type two_process_in_r is record
60	    WrAddr         : unsigned(log2ceil(depth_g) downto 0); -- One additional bit for full/empty detection
61	    WrAddrGray     : std_logic_vector(log2ceil(depth_g) downto 0);
62	    RdAddrGraySync : std_logic_vector(log2ceil(depth_g) downto 0);
63	    RdAddrGray     : std_logic_vector(log2ceil(depth_g) downto 0);
64	    RdAddr         : unsigned(log2ceil(depth_g) downto 0);
65	  end record;
66	
67	  type two_process_out_r is record
68	    RdAddr         : unsigned(log2ceil(depth_g) downto 0); -- One additional bit for full/empty detection
69	    RdAddrGray     : std_logic_vector(log2ceil(depth_g) downto 0);
70	    WrAddrGraySync : std_logic_vector(log2ceil(depth_g) downto 0);
71	    WrAddrGray     : std_logic_vector(log2ceil(depth_g) downto 0);
72	    WrAddr         : unsigned(log2ceil(depth_g) downto 0);
73	    out_lvl_o      : unsigned(log2ceil(depth_g) downto 0);
74	  end record;
75	
76	  signal ri, ri_next : two_process_in_r  := (WrAddr         => (others => '0'),
77	                                             WrAddrGray     => (others => '0'),
78	                                             RdAddrGraySync => (others => '0'),
79	                                             RdAddrGray     => (others => '0'),
80	                                             RdAddr         => (others => '0'));
81	  signal ro, ro_next : two_process_out_r := (RdAddr         => (others => '0'),
82	                                             RdAddrGray     => (others => '0'),
83	                                             WrAddrGraySync => (others => '0'),
84	                                             WrAddrGray     => (others => '0'),
85	                                             WrAddr         => (others => '0'),
86	                                             out_lvl_o      => (others => '0'));
87	
88	  signal RstInInt  : std_logic;
89	  signal RstOutInt : std_logic;
90	  signal RamWr     : std_logic;
91	  signal RamRdAddr : std_logic_vector(log2ceil(depth_g) - 1 downto 0);
92	  signal RamWrAddr : std_logic_vector(log2ceil(depth_g) - 1 downto 0);
93	
94	  attribute syn_srlstyle : string;
95	  attribute syn_srlstyle of ri : signal is "registers";
96	  attribute syn_srlstyle of ro : signal is "registers";
97	
98	  attribute shreg_extract : string;
99	  attribute shreg_extract of ri : signal is "no";
100	  attribute shreg_extract of ro : signal is "no";
101	
102	  attribute ASYNC_REG : string;
103	  attribute ASYNC_REG of ri : signal is "TRUE";
104	  attribute ASYNC_REG of ro : signal is "TRUE";
105	
106	begin
107	
108	  assert log2(depth_g) = log2ceil(depth_g) report "###ERROR###: psi_common_async_fifo: only power of two depth_g is allowed" severity error;
109	
110	  p_comb : process(in_vld_i, out_rdy_i, ri, ro, RstInInt)
111	    variable vi        : two_process_in_r;
112	    variable vo        : two_process_out_r;
113	    variable InLevel_v : unsigned(log2ceil(depth_g) downto 0);
114	  begin
115	    -- *** hold variables stable ***
116	    vi := ri;
117	    vo := ro;
118	
119	    -- *** Write Side ***
120	    -- Defaults
121	    in_rdy_o    <= '0';
122	    in_full_o   <= '0';
123	    in_empty_o  <= '0';
124	    in_afull_o  <= '0';
125	    in_aempty_o <= '0';
126	    RamWr       <= '0';
127	
128	    -- Level Detection
129	    InLevel_v := ri.WrAddr - ri.RdAddr;
130	    in_lvl_o  <= std_logic_vector(InLevel_v);
131	
132	    -- Full
133	    if InLevel_v = depth_g then
134	      in_full_o <= '1';
135	    else
136	      in_rdy_o <= '1';
137	      -- Execute Write
138	      if in_vld_i = '1' then
139	        vi.WrAddr := ri.WrAddr + 1;
140	        RamWr     <= '1';
141	      end if;
142	    end if;
143	    -- Artificially keep InRdy low during reset if required
144	    if (rdy_rst_state_g = '0') and (RstInInt = rst_pol_g) then
145	      in_rdy_o <= '0';
146	    end if;
147	
148	    -- Status Detection
149	    if InLevel_v = 0 then
150	      in_empty_o <= '1';
151	    end if;
152	    if InLevel_v >= afull_lvl_g and afull_on_g then
153	      in_afull_o <= '1';
154	    end if;
155	    if InLevel_v <= aempty_level_g and aempty_on_g then
156	      in_aempty_o <= '1';
157	    end if;
158	
159	    -- *** Read Side ***
160	    -- Defaults
161	    out_vld_o    <= '0';
162	    out_full_o   <= '0';
163	    out_empty_o  <= '0';
164	    out_afull_o  <= '0';
165	    out_aempty_o <= '0';
166	
167	    -- Level Detection
168	    if ro.WrAddr = ro.RdAddr then
169	      vo.out_lvl_o := (others => '0');
170	    else
171	      vo.out_lvl_o := ro.WrAddr - ro.RdAddr;
172	      if (out_rdy_i = '1') and (ro.out_lvl_o /= 0) then
173	        vo.out_lvl_o := vo.out_lvl_o - 1;
174	      end if;
175	    end if;
176	    out_lvl_o <= std_logic_vector(ro.out_lvl_o);
177	
178	    -- Empty
179	    if ro.out_lvl_o = 0 then
180	      out_empty_o <= '1';
181	    else
182	      out_vld_o <= '1';
183	      -- Execute read
184	      if out_rdy_i = '1' then
185	        vo.RdAddr := ro.RdAddr + 1;
186	      end if;
187	    end if;
188	    RamRdAddr <= std_logic_vector(vo.RdAddr(log2ceil(depth_g) - 1 downto 0));
189	
190	    -- Status Detection
191	    if ro.out_lvl_o = depth_g then
192	      out_full_o <= '1';
193	    end if;
194	    if ro.out_lvl_o >= afull_lvl_g and afull_on_g then
195	      out_afull_o <= '1';
196	    end if;
197	    if ro.out_lvl_o <= aempty_level_g and aempty_on_g then
198	      out_aempty_o <= '1';
199	    end if;
200	
201	    -- *** Address Clock domain crossings ***
202	    -- Bin->Gray is simple, can be done without additional FF
203	    vi.WrAddrGray := binary_to_gray(std_logic_vector(vi.WrAddr));
204	    vo.RdAddrGray := binary_to_gray(std_logic_vector(vo.RdAddr));
205	
206	    -- Two stage synchronizer
207	    vi.RdAddrGraySync := ro.RdAddrGray;
208	    vi.RdAddrGray     := ri.RdAddrGraySync;
209	    vo.WrAddrGraySync := ri.WrAddrGray;
210	    vo.WrAddrGray     := ro.WrAddrGraySync;
211	
212	    -- Gray->Bin involves some logic, needs additional FF
213	    vi.RdAddr := unsigned(gray_to_binary(ri.RdAddrGray));
214	    vo.WrAddr := unsigned(gray_to_binary(ro.WrAddrGray));
215	
216	    -- *** Assign signal ***
217	    ri_next <= vi;
218	    ro_next <= vo;
219	
220	  end process;
221	
222	  p_seq_in : process(in_clk_i)
223	  begin
224	    if rising_edge(in_clk_i) then
225	      ri <= ri_next;
226	      if RstInInt = rst_pol_g then
227	        ri.WrAddr         <= (others => '0');
228	        ri.WrAddrGray     <= (others => '0');
229	        ri.RdAddrGraySync <= (others => '0');
230	        ri.RdAddrGray     <= (others => '0');
231	        ri.RdAddr         <= (others => '0');
232	      end if;
233	    end if;
234	  end process;
235	
236	  p_seq_out : process(out_clk_i)
237	  begin
238	    if rising_edge(out_clk_i) then
239	      ro <= ro_next;
240	      if RstOutInt = rst_pol_g then
241	        ro.RdAddr         <= (others => '0');
242	        ro.RdAddrGray     <= (others => '0');
243	        ro.WrAddrGraySync <= (others => '0');
244	        ro.WrAddrGray     <= (others => '0');
245	        ro.WrAddr         <= (others => '0');
246	        ro.out_lvl_o      <= (others => '0');
247	      end if;
248	    end if;
249	  end process;
250	
251	  RamWrAddr <= std_logic_vector(ri.WrAddr(log2ceil(depth_g) - 1 downto 0));
252	  i_ram : entity work.psi_common_sdp_ram
253	    generic map(
254	      depth_g        => depth_g,
255	      width_g        => width_g,
256	      ram_style_g    => ram_style_g,
257	      is_async_g     => true,
258	      ram_behavior_g => ram_behavior_g
259	    )
260	    port map(
261	      -- Port A
262	      wr_clk_i  => in_clk_i,
263	      wr_addr_i => RamWrAddr,
264	      wr_i      => RamWr,
265	      wr_dat_i  => in_dat_i,
266	      -- Port B
267	      rd_clk_i  => out_clk_i,
268	      rd_addr_i => RamRdAddr,
269	      rd_i      => '1',
270	      rd_dat_o  => out_dat_o
271	    );
272	
273	  -- only used for reset crossing and oring
274	  i_rst_cc : entity work.psi_common_pulse_cc
275	      generic map(
276	        a_rst_pol_g => rst_pol_g,
277	        b_rst_pol_g => rst_pol_g
278	      )
279	    port map(
280	      -- Clock Domain A
281	      a_clk_i => in_clk_i,
282	      a_rst_i => in_rst_i,
283	      a_rst_o => RstInInt,
284	      a_dat_i => (others => '0'),
285	      -- Clock Domain B
286	      b_clk_i => out_clk_i,
287	      b_rst_i => out_rst_i,
288	      b_rst_o => RstOutInt,
289	      b_dat_o => open
290	    );
291	end architecture;
292

