67	  return std_logic_vector;
68	
69	end psi_common_logic_pkg;
70	
71	------------------------------------------------------------------------------
72	-- Package Body
73	------------------------------------------------------------------------------
74	package body psi_common_logic_pkg is
75	
76	  -- *** ZerosVector ***
77	  function zeros_vector(size : in natural) return std_logic_vector is
78	    constant c : std_logic_vector(size - 1 downto 0) := (others => '0');
79	  begin
80	    return c;
81	  end function;
82	
83	  -- *** OnesVector ***
84	  function ones_vector(size : in natural) return std_logic_vector is
85	    constant c : std_logic_vector(size - 1 downto 0) := (others => '1');
86	  begin
87	    return c;
88	  end function;
89	
90	  -- *** PartiallyOnesVector ***
91	  function partially_ones_vector(size    : in natural;
92	                                 ones_nb : in natural)
93	  return std_logic_vector is
94	    variable v_low    : std_logic_vector(size downto 0);
95	    variable v_high   : std_logic_vector(size downto 0);
96	    variable v_plus_1 : std_logic_vector(size + 1 downto 0); -- We need this to avoid synthesis problems with Xilinx ISE
97	    variable v        : std_logic_vector(size - 1 downto 0);
98	  begin
99	    v_low    := (others => '1');
100	    v_high   := (others => '0');
101	    v_plus_1 := v_high(size - ones_nb downto 0) & v_low(ones_nb downto 0);
102	    v        := v_plus_1(size downto 1);
103	    return v;
104	  end function;
105	
106	  -- *** ShiftLeft ***
107	  function shift_left(arg  : in std_logic_vector;
108	                      bits : in integer;
109	                      fill : in std_logic := '0')
110	  return std_logic_vector is
111	    constant argDt : std_logic_vector(arg'high downto arg'low) := arg;
112	    variable v     : std_logic_vector(argDt'range);
113	  begin
114	    if bits < 0 then
115	      return shift_right(argDt, -bits, fill);
116	    else
117	      v(v'left downto bits)      := argDt(argDt'left - bits downto argDt'right);
118	      v(bits - 1 downto v'right) := (others => fill);
119	      return v;
120	    end if;
121	  end function;
122	
123	  -- *** ShiftRight ***
124	  function shift_right(arg  : in std_logic_vector;
125	                       bits : in integer;
126	                       fill : in std_logic := '0')
127	  return std_logic_vector is
128	    constant argDt : std_logic_vector(arg'high downto arg'low) := arg;
129	    variable v     : std_logic_vector(argDt'range);
130	  begin
131	    if bits < 0 then
132	      return shift_left(argDt, -bits, fill);
133	    else
134	      v(v'left - bits downto v'right)    := argDt(argDt'left downto bits);
135	      v(v'left downto v'left - bits + 1) := (others => fill);
136	      return v;
137	    end if;
138	  end function;
139	
140	  -- *** BinaryToGray ***
141	  function binary_to_gray(binary : in std_logic_vector)
142	  return std_logic_vector is
143	    variable Gray_v : std_logic_vector(binary'range);
144	  begin
145	    Gray_v := binary xor ('0' & binary(binary'high downto binary'low + 1));
146	    return Gray_v;
147	  end function;
148	
149	  -- *** GrayToBinary ***
150	  function gray_to_binary(gray : in std_logic_vector)
151	  return std_logic_vector is
152	    variable Binary_v : std_logic_vector(gray'range);
153	  begin
154	    Binary_v(Binary_v'high) := gray(gray'high);
155	    for b in gray'high - 1 downto gray'low loop
156	      Binary_v(b) := gray(b) xor Binary_v(b + 1);
157	    end loop;
158	    return Binary_v;
159	  end function;
160	
161	  -- *** PpcOr ***
162	  function ppc_or(inp : in std_logic_vector)
163	  return std_logic_vector is
164	    constant Stages_c    : integer := log2ceil(inp'length);
165	    constant Pwr2Width_c : integer := 2**Stages_c;
166	    type StageOut_t is array (natural range <>) of std_logic_vector(Pwr2Width_c - 1 downto 0);
167	    variable StageOut_v  : StageOut_t(0 to Stages_c);
168	    variable BinCnt_v    : unsigned(Pwr2Width_c - 1 downto 0);
169	  begin
170	    StageOut_v(0)                          := (others => '0');
171	    StageOut_v(0)(inp'length - 1 downto 0) := inp;
172	    for stage in 0 to Stages_c - 1 loop
173	      BinCnt_v := (others => '0');
174	      for idx in 0 to Pwr2Width_c - 1 loop
175	        if BinCnt_v(stage) = '0' then
176	          StageOut_v(stage + 1)(idx) := StageOut_v(stage)(idx) or StageOut_v(stage)((idx / (2**stage) + 1) * 2**stage);
177	        else
178	          StageOut_v(stage + 1)(idx) := StageOut_v(stage)(idx);
179	        end if;
180	        BinCnt_v := BinCnt_v + 1;
181	      end loop;
182	    end loop;
183	    return StageOut_v(Stages_c)(inp'length - 1 downto 0);
184	  end function;
185	
186	  function int_to_std_logic(int : in integer)
187	  return std_logic is
188	  begin
189	    if int = 1 then
190	      return '1';
191	    elsif int = 0 then
192	      return '0';
193	    else
194	      return 'X';
195	    end if;
196	  end function;
197	
198	  function reduce_or(vec : in std_logic_vector)
199	  return std_logic is
200	    variable tmp : std_logic;
201	  begin
202	    tmp := '0';
203	    for i in vec'low to vec'high loop
204	      tmp := tmp or vec(i);
205	    end loop;
206	    return tmp;
207	  end function;
208	
209	  function reduce_and(vec : in std_logic_vector)
210	  return std_logic is
211	    variable tmp : std_logic;
212	  begin
213	    tmp := '1';
214	    for i in vec'low to vec'high loop
215	      tmp := tmp and vec(i);
216	    end loop;
217	    return tmp;
218	  end function;
219	
220	  function to_01X(inp : in std_logic)
221	  return std_logic is
222	  begin
223	    case inp is
224	      when '0' | 'L' => return '0';
225	      when '1' | 'H' => return '1';
226	      when others    => return 'X';
227	    end case;
228	  end function;
229	
230	  function to_01X(inp : in std_logic_vector)
231	  return std_logic_vector is
232	    variable tmp : std_logic_vector(inp'range);
233	  begin
234	    for i in inp'low to inp'high loop
235	      tmp(i) := to_01X(inp(i));
236	    end loop;
237	    return tmp;
238	  end function;
239	
240	  function invert_bit_order(inp : in std_logic_vector)
241	  return std_logic_vector is
242	    variable tmp : std_logic_vector(inp'range);
243	  begin
244	    for i in inp'low to inp'high loop
245	      tmp(tmp'high - i) := inp(i);
246	    end loop;
247	    return tmp;
248	  end function;
249	
250	end package body;

