6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library work;
15	use work.psi_tb_txt_util.all;
16	use work.psi_common_math_pkg.all;
17	use work.psi_common_logic_pkg.all;
18	
19	entity psi_common_async_fifo_tb is
20	  generic(
21	    afull_on_g      : boolean              := true;
22	    aempty_on_g     : boolean              := true;
23	    depth_g         : natural              := 32;
24	    ram_behavior_g  : string               := "RBW";
25	    rdy_rst_state_g : integer range 0 to 1 := 1;
26	    rst_pol_g       : std_logic            := '1'
27	  );
28	end entity psi_common_async_fifo_tb;
29	
30	architecture sim of psi_common_async_fifo_tb is
31	
32	  -------------------------------------------------------------------------
33	  -- Constants
34	  -------------------------------------------------------------------------
35	  constant DataWidth_c     : integer := 16;
36	  constant AlmFullLevel_c  : natural := depth_g - 3;
37	  constant AlmEmptyLevel_c : natural := 5;
38	
39	  -------------------------------------------------------------------------
40	  -- TB Defnitions
41	  -------------------------------------------------------------------------
42	  constant ClockInFrequency_c  : real    := 100.0e6;
43	  constant ClockInPeriod_c     : time    := (1 sec) / ClockInFrequency_c;
44	  constant ClockOutFrequency_c : real    := 83.333e6;
45	  constant ClockOutPeriod_c    : time    := (1 sec) / ClockOutFrequency_c;
46	  signal TbRunning             : boolean := True;
47	
48	  shared variable CheckNow : boolean := False;
49	
50	  -------------------------------------------------------------------------
51	  -- Interface Signals
52	  -------------------------------------------------------------------------
53	  signal in_clk_i     : std_logic                                            := '0';
54	  signal in_rst_i     : std_logic                                            := rst_pol_g;
55	  signal out_clk_i    : std_logic                                            := '0';
56	  signal out_rst_i    : std_logic                                            := rst_pol_g;
57	  signal in_dat_i     : std_logic_vector(DataWidth_c - 1 downto 0)           := (others => '0');
58	  signal in_vld_i     : std_logic                                            := '0';
59	  signal in_rdy_o     : std_logic                                            := '0';
60	  signal out_dat_o    : std_logic_vector(DataWidth_c - 1 downto 0)           := (others => '0');
61	  signal out_vld_o    : std_logic                                            := '0';
62	  signal out_rdy_i    : std_logic                                            := '0';
63	  signal in_full_o    : std_logic                                            := '0';
64	  signal out_full_o   : std_logic                                            := '0';
65	  signal in_empty_o   : std_logic                                            := '0';
66	  signal out_empty_o  : std_logic                                            := '0';
67	  signal in_afull_o   : std_logic                                            := '0';
68	  signal out_afull_o  : std_logic                                            := '0';
69	  signal in_aempty_o  : std_logic                                            := '0';
70	  signal out_aempty_o : std_logic                                            := '0';
71	  signal in_lvl_o     : std_logic_vector(log2ceil(depth_g + 1) - 1 downto 0) := (others => '0');
72	  signal out_lvl_o    : std_logic_vector(log2ceil(depth_g + 1) - 1 downto 0) := (others => '0');
73	
74	begin
75	
76	  -------------------------------------------------------------------------
77	  -- DUT
78	  -------------------------------------------------------------------------
79	  i_dut : entity work.psi_common_async_fifo
80	    generic map(
81	      width_g         => DataWidth_c,
82	      depth_g         => depth_g,
83	      afull_on_g      => afull_on_g,
84	      afull_lvl_g     => AlmFullLevel_c,
85	      aempty_on_g     => aempty_on_g,
86	      aempty_level_g  => AlmEmptyLevel_c,
87	      ram_behavior_g  => ram_behavior_g,
88	      rdy_rst_state_g => int_to_std_logic(rdy_rst_state_g),
89	      rst_pol_g       => rst_pol_g
90	    )
91	    port map(
92	      -- Control Ports
93	      in_clk_i     => in_clk_i,
94	      in_rst_i     => in_rst_i,
95	      out_clk_i    => out_clk_i,
96	      out_rst_i    => out_rst_i,
97	      -- Input Data
98	      in_dat_i     => in_dat_i,
99	      in_vld_i     => in_vld_i,
100	      in_rdy_o     => in_rdy_o,
101	      -- Output Data
102	      out_dat_o    => out_dat_o,
103	      out_vld_o    => out_vld_o,
104	      out_rdy_i    => out_rdy_i,
105	      -- Input Status
106	      in_full_o    => in_full_o,
107	      in_empty_o   => in_empty_o,
108	      in_afull_o   => in_afull_o,
109	      in_aempty_o  => in_aempty_o,
110	      in_lvl_o     => in_lvl_o,
111	      -- Output Status
112	      out_full_o   => out_full_o,
113	      out_empty_o  => out_empty_o,
114	      out_afull_o  => out_afull_o,
115	      out_aempty_o => out_aempty_o,
116	      out_lvl_o    => out_lvl_o
117	    );
118	
119	  -------------------------------------------------------------------------
120	  -- Clock
121	  -------------------------------------------------------------------------
122	  p_clk_in : process
123	  begin
124	    in_clk_i <= '0';
125	    while TbRunning loop
126	      wait for 0.5 * ClockInPeriod_c;
127	      in_clk_i <= '1';
128	      wait for 0.5 * ClockInPeriod_c;
129	      in_clk_i <= '0';
130	    end loop;
131	    wait;
132	  end process;
133	
134	  p_clk_out : process
135	  begin
136	    out_clk_i <= '0';
137	    while TbRunning loop
138	      wait for 0.5 * ClockOutPeriod_c;
139	      out_clk_i <= '1';
140	      wait for 0.5 * ClockOutPeriod_c;
141	      out_clk_i <= '0';
142	    end loop;
143	    wait;
144	  end process;
145	
146	  -------------------------------------------------------------------------
147	  -- TB Control
148	  -------------------------------------------------------------------------
149	  p_control : process
150	  begin
151	    -- *** Reset Tests ***
152	    print(">> Reset");
153	    -- Reset
154	    in_rst_i  <= rst_pol_g;
155	    out_rst_i <= rst_pol_g;
156	    -- check if ready state during reset is correct
157	    wait for 20 ns;                     -- reset must be transferred to other clock domain
158	    wait until rising_edge(in_clk_i);
159	    assert in_rdy_o = int_to_std_logic(rdy_rst_state_g) report "###ERROR###: in_rdy_o reset state not according to generic" severity error;
160	    wait for 1 us;
161	
162	    -- Remove reset
163	    wait until rising_edge(in_clk_i);
164	    in_rst_i  <= not rst_pol_g;
165	    wait until rising_edge(out_clk_i);
166	    out_rst_i <= not rst_pol_g;
167	    wait for 100 ns;
168	
169	    -- Check Reset State
170	    wait until rising_edge(in_clk_i);
171	    assert in_rdy_o = '1' report "###ERROR###: in_rdy_o after reset state not '1'" severity error;
172	    assert in_full_o = '0' report "###ERROR###: in_full_o reset state not '0'" severity error;
173	    assert in_empty_o = '1' report "###ERROR###: in_empty_o reset state not '1'" severity error;
174	    assert unsigned(in_lvl_o) = 0 report "###ERROR###: in_lvl_o reset state not 0" severity error;
175	    if afull_on_g then
176	      assert in_afull_o = '0' report "###ERROR###: in_afull_o reset state not '0'" severity error;
177	    end if;
178	    if aempty_on_g then
179	      assert in_aempty_o = '1' report "###ERROR###: in_aempty_o reset state not '1'" severity error;
180	    end if;
181	
182	    wait until rising_edge(out_clk_i);
183	    assert out_vld_o = '0' report "###ERROR###: out_vld_o reset state not '0'" severity error;
184	    assert out_full_o = '0' report "###ERROR###: out_full_o reset state not '0'" severity error;
185	    assert out_empty_o = '1' report "###ERROR###: out_empty_o reset state not '1'" severity error;
186	    assert unsigned(out_lvl_o) = 0 report "###ERROR###: out_lvl_o reset state not 0" severity error;
187	    if afull_on_g then
188	      assert out_afull_o = '0' report "###ERROR###: out_afull_o reset state not '0'" severity error;
189	    end if;
190	    if aempty_on_g then
191	      assert out_aempty_o = '1' report "###ERROR###: out_aempty_o reset state not '1'" severity error;
192	    end if;
193	
194	    -- *** Two words write then read ***
195	    print(">> Two words write then read");
196	    -- Write 1
197	    wait until falling_edge(in_clk_i);
198	    in_dat_i  <= X"0001";
199	    in_vld_i  <= '1';
200	    assert in_rdy_o = '1' report "###ERROR###: in_rdy_o went low unexpectedly" severity error;
201	    assert in_empty_o = '1' report "###ERROR###: in_empty_o not high" severity error;
202	    assert unsigned(in_lvl_o) = 0 report "###ERROR###: in_lvl_o not 0" severity error;
203	    -- Write 2
204	    wait until falling_edge(in_clk_i);
205	    in_dat_i  <= X"0002";
206	    assert in_rdy_o = '1' report "###ERROR###: in_rdy_o went low unexpectedly" severity error;
207	    assert in_empty_o = '0' report "###ERROR###: Empty not low" severity error;
208	    assert unsigned(in_lvl_o) = 1 report "###ERROR###: in_lvl_o not 1" severity error;
209	    -- Pause 1
210	    wait until falling_edge(in_clk_i);
211	    in_dat_i  <= X"0003";
212	    in_vld_i  <= '0';
213	    assert in_rdy_o = '1' report "###ERROR###: in_rdy_o went low unexpectedly" severity error;
214	    assert in_empty_o = '0' report "###ERROR###: Empty not low" severity error;
215	    assert unsigned(in_lvl_o) = 2 report "###ERROR###: in_lvl_o not 2" severity error;
216	    -- Pause 2
217	    for i in 0 to 4 loop
218	      wait until falling_edge(in_clk_i);
219	      wait until falling_edge(out_clk_i);
220	    end loop;
221	    assert in_rdy_o = '1' report "###ERROR###: in_rdy_o went low unexpectedly" severity error;
222	    assert out_vld_o = '1' report "###ERROR###: out_vld_o not high" severity error;
223	    assert out_dat_o = X"0001" report "###ERROR###: Illegal out_dat_o 1" severity error;
224	    assert in_empty_o = '0' report "###ERROR###: in_empty_o not low" severity error;
225	    assert in_full_o = '0' report "###ERROR###: in_full_o not low" severity error;
226	    assert out_empty_o = '0' report "###ERROR###: in_empty_o not low" severity error;
227	    assert out_full_o = '0' report "###ERROR###: in_full_o not low" severity error;
228	    assert unsigned(in_lvl_o) = 2 report "###ERROR###: in_lvl_o not 2" severity error;
229	    assert unsigned(out_lvl_o) = 2 report "###ERROR###: out_lvl_o not 2" severity error;
230	    -- Read ack 1
231	    wait until falling_edge(out_clk_i);
232	    out_rdy_i <= '1';
233	    assert out_vld_o = '1' report "###ERROR###: out_vld_o not high" severity error;
234	    assert out_dat_o = X"0001" report "###ERROR###: Illegal out_dat_o 1" severity error;
235	    assert out_empty_o = '0' report "###ERROR###: Empty not low" severity error;
236	    assert unsigned(out_lvl_o) = 2 report "###ERROR###: out_lvl_o not 2" severity error;
237	    -- Read ack 2
238	    wait until falling_edge(out_clk_i);
239	    assert out_vld_o = '1' report "###ERROR###: out_vld_o not high" severity error;
240	    assert out_dat_o = X"0002" report "###ERROR###: Illegal out_dat_o 2" severity error;
241	    assert out_empty_o = '0' report "###ERROR###: Empty not low" severity error;
242	    assert unsigned(out_lvl_o) = 1 report "###ERROR###: out_lvl_o not 1" severity error;
243	    -- empty 1
244	    wait until falling_edge(out_clk_i);
245	    out_rdy_i <= '0';
246	    assert out_vld_o = '0' report "###ERROR###: out_vld_o not high" severity error;
247	    assert out_empty_o = '1' report "###ERROR###: Empty not high" severity error;
248	    assert unsigned(out_lvl_o) = 0 report "###ERROR###: out_lvl_o not 0" severity error;
249	    -- empty 2
250	    for i in 0 to 4 loop
251	      wait until falling_edge(out_clk_i);
252	      wait until falling_edge(in_clk_i);
253	    end loop;
254	    assert in_rdy_o = '1' report "###ERROR###: in_rdy_o went low unexpectedly" severity error;
255	    assert out_vld_o = '0' report "###ERROR###: out_vld_o not high" severity error;
256	    assert in_empty_o = '1' report "###ERROR###: in_empty_o not high" severity error;
257	    assert out_empty_o = '1' report "###ERROR###: out_empty_o not high" severity error;
258	    assert in_full_o = '0' report "###ERROR###: in_full_o not low" severity error;
259	    assert out_full_o = '0' report "###ERROR###: out_full_o not low" severity error;
260	    assert unsigned(in_lvl_o) = 0 report "###ERROR###: in_lvl_o not 0" severity error;
261	    assert unsigned(out_lvl_o) = 0 report "###ERROR###: out_lvl_o not 0" severity error;
262	
263	    -- *** Write into Full FIFO ***
264	    wait until falling_edge(in_clk_i);
265	    print(">> Write into Full FIFO");
266	    -- Fill FIFO
267	    for i in 0 to depth_g - 1 loop
268	      in_vld_i <= '1';
269	      in_dat_i <= std_logic_vector(to_unsigned(i, in_dat_i'length));
270	      wait until falling_edge(in_clk_i);
271	    end loop;
272	    in_vld_i  <= '0';
273	    wait for 1 us;
274	    assert in_full_o = '1' report "###ERROR###: in_full_o not asserted" severity error;
275	    assert out_full_o = '1' report "###ERROR###: out_full_o not asserted" severity error;
276	    assert unsigned(in_lvl_o) = depth_g report "###ERROR###: in_lvl_o not full" severity error;
277	    assert unsigned(out_lvl_o) = depth_g report "###ERROR###: out_lvl_o not full" severity error;
278	    -- Add more data (not written because full)
279	    wait until falling_edge(in_clk_i);
280	    in_vld_i  <= '1';
281	    in_dat_i  <= X"ABCD";
282	    wait until falling_edge(in_clk_i);
283	    in_dat_i  <= X"8765";
284	    wait until falling_edge(in_clk_i);
285	    in_vld_i  <= '0';
286	    wait for 1 us;
287	    assert in_full_o = '1' report "###ERROR###: in_full_o not asserted" severity error;
288	    assert out_full_o = '1' report "###ERROR###: out_full_o not asserted" severity error;
289	    assert unsigned(in_lvl_o) = depth_g report "###ERROR###: in_lvl_o not full" severity error;
290	    assert unsigned(out_lvl_o) = depth_g report "###ERROR###: out_lvl_o not full" severity error;
291	    -- Check read
292	    wait until falling_edge(out_clk_i);
293	    for i in 0 to depth_g - 1 loop
294	      out_rdy_i <= '1';
295	      assert unsigned(out_dat_o) = i report "###ERROR: Read wrong data in word " & integer'image(i) severity error;
296	      wait until falling_edge(out_clk_i);
297	    end loop;
298	    out_rdy_i <= '0';
299	    wait for 1 us;
300	    assert in_empty_o = '1' report "###ERROR###: in_empty_o not asserted" severity error;
301	    assert out_empty_o = '1' report "###ERROR###: out_empty_o not asserted" severity error;
302	    assert in_full_o = '0' report "###ERROR###: in_full_o not de-asserted" severity error;
303	    assert out_full_o = '0' report "###ERROR###: out_full_o not de-asserted" severity error;
304	
305	    -- *** Read from Empty Fifo ***
306	    wait until falling_edge(out_clk_i);
307	    print(">> Read from Empty FIFO");
308	    assert out_empty_o = '1' report "###ERROR###: out_empty_o not asserted" severity error;
309	    assert in_empty_o = '1' report "###ERROR###: in_empty_o not asserted" severity error;
310	    -- read
311	    wait until falling_edge(out_clk_i);
312	    out_rdy_i <= '1';
313	    wait until falling_edge(out_clk_i);
314	    out_rdy_i <= '0';
315	    -- check correct functionality
316	    wait for 1 us;
317	    assert out_empty_o = '1' report "###ERROR###: out_empty_o not asserted" severity error;
318	    assert in_empty_o = '1' report "###ERROR###: in_empty_o not asserted" severity error;
319	    assert unsigned(in_lvl_o) = 0 report "###ERROR###: in_lvl_o not empty" severity error;
320	    assert unsigned(out_lvl_o) = 0 report "###ERROR###: out_lvl_o not empty" severity error;
321	    wait until falling_edge(in_clk_i);
322	    in_vld_i  <= '1';
323	    in_dat_i  <= X"8765";
324	    wait until falling_edge(in_clk_i);
325	    in_vld_i  <= '0';
326	    wait for 1 us;
327	    assert out_empty_o = '0' report "###ERROR###: out_empty_o not de-asserted" severity error;
328	    assert in_empty_o = '0' report "###ERROR###: in_empty_o not de-asserted" severity error;
329	    assert unsigned(in_lvl_o) = 1 report "###ERROR###: in_lvl_o not empty" severity error;
330	    assert unsigned(out_lvl_o) = 1 report "###ERROR###: out_lvl_o not empty" severity error;
331	    wait until falling_edge(out_clk_i);
332	    assert out_dat_o = X"8765" report "###ERROR: Read wrong data" severity error;
333	    out_rdy_i <= '1';
334	    wait until falling_edge(out_clk_i);
335	    out_rdy_i <= '0';
336	    wait for 1 us;
337	    assert out_empty_o = '1' report "###ERROR###: out_empty_o not asserted" severity error;
338	    assert in_empty_o = '1' report "###ERROR###: in_empty_o not asserted" severity error;
339	    assert unsigned(in_lvl_o) = 0 report "###ERROR###: in_lvl_o not empty" severity error;
340	    assert unsigned(out_lvl_o) = 0 report "###ERROR###: out_lvl_o not empty" severity error;
341	
342	    -- *** Almost full/almost empty
343	    print(">> Almost full/almost empty");
344	    -- fill
345	    for i in 0 to depth_g - 1 loop
346	      wait until falling_edge(in_clk_i);
347	      in_vld_i <= '1';
348	      in_dat_i <= std_logic_vector(to_unsigned(i, in_dat_i'length));
349	      wait until falling_edge(in_clk_i);
350	      in_vld_i <= '0';
351	      wait for 1 us;
352	      assert unsigned(in_lvl_o) = i + 1 report "###ERROR###: in_lvl_o wrong" severity error;
353	      assert unsigned(out_lvl_o) = i + 1 report "###ERROR###: out_lvl_o wrong" severity error;
354	      if afull_on_g then
355	        if i + 1 >= AlmFullLevel_c then
356	          assert in_afull_o = '1' report "###ERROR###: InAlmost Full not set" severity error;
357	          assert out_afull_o = '1' report "###ERROR###: OutAlmost Full not set" severity error;
358	        else
359	          assert in_afull_o = '0' report "###ERROR###: InAlmost Full set" severity error;
360	          assert out_afull_o = '0' report "###ERROR###: OutAlmost Full set" severity error;
361	        end if;
362	      end if;
363	      if aempty_on_g then
364	        if i + 1 <= AlmEmptyLevel_c then
365	          assert in_aempty_o = '1' report "###ERROR###: InAlmost Empty not set" severity error;
366	          assert out_aempty_o = '1' report "###ERROR###: OutAlmost Empty not set" severity error;
367	        else
368	          assert in_aempty_o = '0' report "###ERROR###: InAlmost Empty set" severity error;
369	          assert out_aempty_o = '0' report "###ERROR###: OutAlmost Empty set" severity error;
370	        end if;
371	      end if;
372	    end loop;
373	    -- flush
374	
375	    for i in depth_g - 1 downto 0 loop
376	      wait until falling_edge(out_clk_i);
377	      out_rdy_i <= '1';
378	      wait until falling_edge(out_clk_i);
379	      out_rdy_i <= '0';
380	      wait for 1 us;
381	      assert unsigned(in_lvl_o) = i report "###ERROR###: in_lvl_o wrong" severity error;
382	      assert unsigned(out_lvl_o) = i report "###ERROR###: out_lvl_o wrong" severity error;
383	      if afull_on_g then
384	        if i >= AlmFullLevel_c then
385	          assert in_afull_o = '1' report "###ERROR###: InAlmost Full not set" severity error;
386	          assert out_afull_o = '1' report "###ERROR###: OutAlmost Full not set" severity error;
387	        else
388	          assert in_afull_o = '0' report "###ERROR###: InAlmost Full set" severity error;
389	          assert out_afull_o = '0' report "###ERROR###: OutAlmost Full set" severity error;
390	        end if;
391	      end if;
392	      if aempty_on_g then
393	        if i <= AlmEmptyLevel_c then
394	          assert in_aempty_o = '1' report "###ERROR###: InAlmost Empty not set" severity error;
395	          assert out_aempty_o = '1' report "###ERROR###: OutAlmost Empty not set" severity error;
396	        else
397	          assert in_aempty_o = '0' report "###ERROR###: InAlmost Empty set" severity error;
398	          assert out_aempty_o = '0' report "###ERROR###: OutAlmost Empty set" severity error;
399	        end if;
400	      end if;
401	    end loop;
402	
403	    -- Different duty cycles
404	    print(">> Different Duty Cycles");
405	    for wrDel in 0 to 4 loop
406	      for rdDel in 0 to 4 loop
407	        assert in_empty_o = '1' report "###ERROR###: in_empty_o not asserted" severity error;
408	        -- Write data
409	        wait until falling_edge(in_clk_i);
410	        for i in 0 to 4 loop
411	          in_vld_i <= '1';
412	          in_dat_i <= std_logic_vector(to_unsigned(i, in_dat_i'length));
413	          wait until falling_edge(in_clk_i);
414	          for k in 1 to wrDel loop
415	            in_vld_i <= '0';
416	            in_dat_i <= X"0000";
417	            wait until falling_edge(in_clk_i);
418	          end loop;
419	        end loop;
420	        in_vld_i  <= '0';
421	        -- Read data
422	        wait until falling_edge(out_clk_i);
423	        for i in 0 to 4 loop
424	          out_rdy_i <= '1';
425	          assert unsigned(out_dat_o) = i report "###ERROR###: Wrong data" severity error;
426	          wait until falling_edge(out_clk_i);
427	          for k in 1 to rdDel loop
428	            out_rdy_i <= '0';
429	            wait until falling_edge(out_clk_i);
430	          end loop;
431	        end loop;
432	        out_rdy_i <= '0';
433	        assert out_empty_o = '1' report "###ERROR###: Empty not asserted" severity error;
434	        wait for 1 us;
435	      end loop;
436	    end loop;
437	
438	    -- Output Ready before data available
439	    print(">> Output Ready before data available");
440	    out_rdy_i <= '1';
441	    for i in 0 to 9 loop
442	      wait until falling_edge(out_clk_i);
443	      wait until falling_edge(in_clk_i);
444	    end loop;
445	    in_dat_i  <= X"ABCD";
446	    in_vld_i  <= '1';
447	    wait until falling_edge(in_clk_i);
448	    in_dat_i  <= X"4321";
449	    wait until falling_edge(in_clk_i);
450	    in_vld_i  <= '0';
451	    wait until out_vld_o = '1' and rising_edge(out_clk_i);
452	    assert out_empty_o = '0' report "###ERROR###: Empty asserted" severity error;
453	    assert out_dat_o = X"ABCD" report "###ERROR###: Wrong data 0" severity error;
454	    wait until out_vld_o = '1' and falling_edge(out_clk_i);
455	    assert out_empty_o = '0' report "###ERROR###: Empty asserted" severity error;
456	    assert out_dat_o = X"4321" report "###ERROR###: Wrong data 1" severity error;
457	    wait until falling_edge(out_clk_i);
458	    assert out_empty_o = '1' report "###ERROR###: Empty not asserted" severity error;
459	    assert out_vld_o = '0' report "###ERROR###: Valid asserted" severity error;
460	
461	    -- TB done
462	    TbRunning <= false;
463	    wait;
464	  end process;
465	
466	end sim;
467

